-- Compute SHA-256 hash of plugin code
local function compute_sha256(data)
    local sha256 = resty_sha256:new()
    if not sha256 then
        return nil, "failed to create sha256 instance"
    end
    sha256:update(data)
    local digest = sha256:final()
    return str.to_hex(digest)
end

-- Compute HMAC-SHA256 for integrity verification
local function compute_hmac(data)
    local resty_hmac = require "resty.hmac"
    local hmac_sha256 = resty_hmac:new(HMAC_SECRET, resty_hmac.ALGOS.SHA256)
    if not hmac_sha256 then
        return nil, "failed to create HMAC instance"
    end
    hmac_sha256:update(data)
    local mac = hmac_sha256:final()
    return str.to_hex(mac)
end

-- Connect to Redis
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "failed to connect to Redis: " .. (err or "unknown")
    end

    return red
end

-- Release Redis connection back to pool
local function release_redis(red)
    if red then
        local ok, err = red:set_keepalive(10000, 100)
        if not ok then
            ngx.log(ngx.WARN, "failed to set Redis keepalive: ", err)
        end
    end
end

-- Validate plugin name against whitelist
local function validate_plugin_name(name)
    if not name or type(name) ~= "string" then
        return false, "plugin name must be a non-empty string"
    end

    -- Strict format: only lowercase alphanumeric and underscores
    if not ngx.re.match(name, "^[a-z][a-z0-9_]{0,63}$", "jo") then
        return false, "plugin name contains invalid characters"
    end

    if not ALLOWED_PLUGIN_NAMES[name] then
        return false, "plugin '" .. name .. "' is not in the approved whitelist"
    end

    return true
end

-- Load plugin code from Redis with integrity verification
-- Plugins must be pre-registered by an admin process that stores both
-- the code and its HMAC signature
local function load_verified_plugin_from_redis(plugin_name)
