    local stored_hmac, err = red:get(PLUGIN_HASH_PREFIX .. plugin_name)
    if not stored_hmac or stored_hmac == ngx.null then
        release_redis(red)
        return nil, "integrity hash not found for plugin '" .. plugin_name .. "'"
    end

    release_redis(red)

    -- Verify HMAC integrity
    local computed_hmac, err = compute_hmac(plugin_code)
    if not computed_hmac then
        return nil, "failed to compute HMAC: " .. (err or "unknown")
    end

    -- Constant-time comparison to prevent timing attacks
    if #computed_hmac ~= #stored_hmac then
        ngx.log(ngx.ERR, "SECURITY: HMAC length mismatch for plugin '", plugin_name, "'")
        return nil, "integrity verification failed for plugin '" .. plugin_name .. "'"
    end

    local mismatch = 0
    for i = 1, #computed_hmac do
        local a = string.byte(computed_hmac, i)
        local b = string.byte(stored_hmac, i)
        -- bitwise XOR via arithmetic for Lua 5.1 compatibility
        mismatch = mismatch + (a == b and 0 or 1)
    end

    if mismatch ~= 0 then
        ngx.log(ngx.ERR, "SECURITY: HMAC verification FAILED for plugin '", plugin_name,
                "'. Plugin code may have been tampered with.")
        return nil, "integrity verification failed for plugin '" .. plugin_name .. "'"
    end

    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' passed integrity verification")
    return plugin_code
