-- Handler for executing plugins via HTTP request
-- Example nginx config:
--   location /gateway/plugin {
--       content_by_lua_block {
--           local loader = require "secure_plugin_loader"
--           loader.handle_request()
--       }
--   }
function _M.handle_request()
    local cjson = require "cjson.safe"

    -- Only accept plugin name from a query parameter (NOT from headers or body code)
    local args = ngx.req.get_uri_args()
    local plugin_name = args.plugin

    if not plugin_name then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({
            error = "missing 'plugin' query parameter",
            allowed_plugins = _M.list_allowed_plugins(),
        }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    -- Build context from request
    local context = {
        method = ngx.req.get_method(),
        uri = ngx.var.uri,
        args = args,
        headers = ngx.req.get_headers(),
        remote_addr = ngx.var.remote_addr,
    }

    -- Execute the plugin
    local result, err = _M.execute_plugin(plugin_name, context)
    if err then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say(cjson.encode({
            error = "plugin execution failed",
            details = err,
        }))
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    -- If plugin returned a table, encode as JSON
    if type(result) == "table" then
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode(result))
    elseif result ~= nil then
        ngx.say(tostring(result))
    end
end

-- Admin handler for registering plugins (must be protected by auth middleware)
-- Example nginx config:
--   location /admin/plugin/register {
--       access_by_lua_block {
--           -- verify admin authentication here
--       }
--       content_by_lua_block {
--           local loader = require "secure_plugin_loader"
--           loader.handle_admin_register()
--       }
--   }
function _M.handle_admin_register()
    local cjson = require "cjson.safe"

    if ngx.req.get_method() ~= "POST" then
        ngx.status = 405
        ngx.say(cjson.encode({ error = "method not allowed" }))
        return ngx.exit(405)
    end

    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({ error = "empty request body" }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local data, decode_err = cjson.decode(body)
    if not data then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({ error = "invalid JSON: " .. (decode_err or "unknown") }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    local ok, err = _M.register_plugin(data.name, data.code)
    if not ok then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({ error = err }))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    ngx.say(cjson.encode({
        success = true,
        message = "plugin '" .. data.name .. "' registered successfully",
    }))
end

